import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';

function Dashboard() {
  const { currentUser, logout, loading } = useAuth();
  const [activeTab, setActiveTab] = useState('overview');
  const [hoveredCard, setHoveredCard] = useState(null);

  useEffect(() => {
    if (!loading && !currentUser) {
      window.location.href = '/login';
    }
  }, [currentUser, loading]);

  if (loading) return (
    <div style={{
      minHeight: '100vh', background: '#080808',
      display: 'flex', alignItems: 'center',
      justifyContent: 'center', flexDirection: 'column', gap: '16px'
    }}>
      <div style={{ fontSize: '48px' }}>🦉</div>
      <div style={{ color: '#22c55e', fontSize: '16px', fontWeight: '500' }}>Loading your nest...</div>
    </div>
  );

  if (!currentUser) return null;

  const navItems = [
    { id: 'overview',  icon: '🏠', label: 'Overview'    },
    { id: 'dsa',       icon: '📊', label: 'DSA Tracker' },
    { id: 'github',    icon: '🐙', label: 'GitHub'      },
    { id: 'ai',        icon: '🤖', label: 'AI Mentor'   },
    { id: 'portfolio', icon: '🌐', label: 'Portfolio'   },
  ];

  const stats = [
    {
      icon: '📊', label: 'Problems Solved',
      value: '0', sub: 'of 25 total',
      color: '#22c55e', bg: 'rgba(34,197,94,0.08)',
      border: 'rgba(34,197,94,0.15)',
      progress: 0,
    },
    {
      icon: '🐙', label: 'GitHub Repos',
      value: '--', sub: 'Connect GitHub',
      color: '#3b82f6', bg: 'rgba(59,130,246,0.08)',
      border: 'rgba(59,130,246,0.15)',
      progress: 0,
    },
    {
      icon: '🔥', label: 'Day Streak',
      value: '1', sub: 'Keep it up!',
      color: '#f59e0b', bg: 'rgba(245,158,11,0.08)',
      border: 'rgba(245,158,11,0.15)',
      progress: 10,
    },
    {
      icon: '🎯', label: 'Readiness Score',
      value: '--', sub: 'Complete profile',
      color: '#a855f7', bg: 'rgba(168,85,247,0.08)',
      border: 'rgba(168,85,247,0.15)',
      progress: 0,
    },
  ];

  const actions = [
    {
      icon: '📊', title: 'Start DSA Practice',
      desc: 'Pick up from where you left off',
      tab: 'dsa', color: '#22c55e',
      tag: 'Most Popular'
    },
    {
      icon: '🐙', title: 'Connect GitHub',
      desc: 'Sync your repos and activity',
      tab: 'github', color: '#3b82f6',
      tag: 'Recommended'
    },
    {
      icon: '🤖', title: 'Get AI Roadmap',
      desc: 'Personalized prep plan for you',
      tab: 'ai', color: '#a855f7',
      tag: 'AI Powered'
    },
    {
      icon: '🌐', title: 'View Portfolio',
      desc: 'See your public profile link',
      tab: 'portfolio', color: '#f59e0b',
      tag: 'Share Ready'
    },
  ];

  return (
    <div style={s.page}>

      {/* ── Sidebar ── */}
      <div style={s.sidebar}>
        {/* Logo */}
        <div style={s.sidebarLogo}>
          <div style={s.logoIconWrap}>
            <span style={{ fontSize: '22px' }}>🦉</span>
          </div>
          <span style={s.logoText}>DevNest</span>
          <span style={s.betaBadge}>BETA</span>
        </div>

        {/* Nav */}
        <div style={s.navSection}>
          <div style={s.navLabel}>MAIN MENU</div>
          {navItems.map(item => (
            <div
              key={item.id}
              style={{
                ...s.navItem,
                ...(activeTab === item.id ? s.navItemActive : {})
              }}
              onClick={() => setActiveTab(item.id)}
            >
              <div style={{
                ...s.navIconWrap,
                background: activeTab === item.id ? 'rgba(34,197,94,0.1)' : 'transparent',
              }}>
                <span style={{ fontSize: '14px' }}>{item.icon}</span>
              </div>
              <span style={s.navItemLabel}>{item.label}</span>
              {activeTab === item.id && <div style={s.navDot}></div>}
            </div>
          ))}
        </div>

        {/* Bottom */}
        <div style={s.sidebarBottom}>
          <div style={s.profileCard}>
            <div style={s.avatar}>
              {currentUser.name?.charAt(0).toUpperCase()}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={s.profileName}>{currentUser.name}</div>
              <div style={s.profileEmail}>{currentUser.email}</div>
            </div>
          </div>
          <button onClick={logout} style={s.logoutBtn}>
            <span>→</span> Sign out
          </button>
        </div>
      </div>

      {/* ── Main ── */}
      <div style={s.main}>

        {/* Top Bar */}
        <div style={s.topBar}>
          <div>
            <h1 style={s.pageTitle}>
              {navItems.find(n => n.id === activeTab)?.label}
            </h1>
            <p style={s.pageDate}>
              {new Date().toLocaleDateString('en-US', {
                weekday: 'long', month: 'long', day: 'numeric', year: 'numeric'
              })}
            </p>
          </div>
          <div style={s.welcomePill}>
            <div style={s.welcomeDot}></div>
            Welcome back, {currentUser.name?.split(' ')[0]} 👋
          </div>
        </div>

        {/* Overview */}
        {activeTab === 'overview' && (
          <div>

            {/* Stats */}
            <div style={s.statsGrid}>
              {stats.map((stat, i) => (
                <div
                  key={stat.label}
                  style={{
                    ...s.statCard,
                    background: hoveredCard === `stat-${i}` ? '#141414' : '#0f0f0f',
                    borderColor: hoveredCard === `stat-${i}` ? stat.border : '#1a1a1a',
                  }}
                  onMouseEnter={() => setHoveredCard(`stat-${i}`)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <div style={s.statTopRow}>
                    <div style={{
                      ...s.statIconBox,
                      background: stat.bg,
                      border: `1px solid ${stat.border}`
                    }}>
                      <span style={{ fontSize: '14px' }}>{stat.icon}</span>
                    </div>
                    <span style={s.statLabelText}>{stat.label}</span>
                  </div>
                  <div style={{ ...s.statValue, color: stat.color }}>
                    {stat.value}
                  </div>
                  <div style={s.statSubText}>{stat.sub}</div>

                  {/* Progress bar */}
                  <div style={s.progressBg}>
                    <div style={{
                      ...s.progressFill,
                      width: `${stat.progress}%`,
                      background: stat.color,
                      boxShadow: `0 0 8px ${stat.color}50`,
                    }}></div>
                  </div>
                </div>
              ))}
            </div>

            {/* Section Title */}
            <div style={s.sectionHeader}>
              <h2 style={s.sectionTitle}>Quick Actions</h2>
              <span style={s.sectionSub}>Get started with these features</span>
            </div>

            {/* Action Cards */}
            <div style={s.actionsGrid}>
              {actions.map((action, i) => (
                <div
                  key={action.title}
                  style={{
                    ...s.actionCard,
                    borderColor: hoveredCard === `action-${i}` ? action.color + '40' : '#1a1a1a',
                    background: hoveredCard === `action-${i}` ? '#141414' : '#0f0f0f',
                    transform: hoveredCard === `action-${i}` ? 'translateY(-3px)' : 'translateY(0)',
                  }}
                  onClick={() => setActiveTab(action.tab)}
                  onMouseEnter={() => setHoveredCard(`action-${i}`)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  {/* Tag */}
                  <div style={{
                    ...s.actionTag,
                    color: action.color,
                    background: action.color + '15',
                    border: `1px solid ${action.color}30`,
                  }}>
                    {action.tag}
                  </div>

                  <div style={{
                    ...s.actionIconBox,
                    background: action.color + '12',
                    border: `1px solid ${action.color}25`,
                  }}>
                    <span style={{ fontSize: '24px' }}>{action.icon}</span>
                  </div>

                  <div style={s.actionTitle}>{action.title}</div>
                  <div style={s.actionDesc}>{action.desc}</div>

                  <div style={{ ...s.actionArrow, color: action.color }}>
                    Explore →
                  </div>
                </div>
              ))}
            </div>

            {/* Banner */}
            <div style={s.banner}>
              <div style={s.bannerLeft}>
                <div style={s.bannerTitle}>🚀 Complete your profile to unlock all features</div>
                <div style={s.bannerSub}>Add your GitHub username and LeetCode handle to get started</div>
              </div>
              <button
                style={s.bannerBtn}
                onClick={() => setActiveTab('github')}
              >
                Complete Profile →
              </button>
            </div>

          </div>
        )}

        {/* Other tabs */}
        {activeTab !== 'overview' && (
          <div style={s.comingSoon}>
            <div style={s.comingSoonGlow}></div>
            <div style={s.comingSoonIcon}>
              {navItems.find(n => n.id === activeTab)?.icon}
            </div>
            <h2 style={s.comingSoonTitle}>
              {navItems.find(n => n.id === activeTab)?.label}
            </h2>
            <p style={s.comingSoonText}>
              This section is under construction. Coming soon!
            </p>
            <button style={s.backBtn} onClick={() => setActiveTab('overview')}>
              ← Back to Overview
            </button>
          </div>
        )}
      </div>

      <style>{`
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 2px; }
      `}</style>
    </div>
  );
}

